Here are the public test cases for feature2_deployment_scripts:
{
  "description": "Attach deployment-only SQL scripts to a database project and report whether the built package carries pre-deployment or post-deployment script payloads without adding those scripts as schema objects.",
  "cases": [
    {
      "input": {
        "sql_files": {
          "Table1.sql": "CREATE TABLE [dbo].[Table1]
(
	c1 int NOT NULL PRIMARY KEY,
	c2 int NULL
)
",
          "Script.PreDeployment1.sql": "-- This file contains SQL statements that will be executed before the build script.
CREATE TABLE Table2 (ID INT NOT NULL, COL1 INT NULL)
GO
"
        },
        "pre_deploy": [
          "Script.PreDeployment1.sql"
        ]
      },
      "expected_output": "exit_code=0
package_exists=true
tables=[dbo].[Table1]
views=
pre_deploy_script=true
post_deploy_script=false
diagnostics=none
"
    },
    {
      "input": {
        "sql_files": {
          "Table1.sql": "CREATE TABLE [dbo].[Table1]
(
	c1 int NOT NULL PRIMARY KEY,
	c2 int NULL
)
",
          "Script.PostDeployment1.sql": "-- This file contains SQL statements that will be executed after the build script.
INSERT INTO Table1 VALUES (1, 2)
GO
INSERT INTO Table1 VALUES (3, 4)
GO
"
        },
        "post_deploy": [
          "Script.PostDeployment1.sql"
        ]
      },
      "expected_output": "exit_code=0
package_exists=true
tables=[dbo].[Table1]
views=
pre_deploy_script=false
post_deploy_script=true
diagnostics=none
"
    }
  ]
}

