    {
      "input": {
        "sql_files": {
          "Table1.sql": "CREATE TABLE [dbo].[Table1]
(
	c1 int NOT NULL PRIMARY KEY,
	c2 int NULL
)
",
          "Table2.sql": "-- This file to be excluded from project by the test
CREATE TABLE [dbo].[Table2]
(
	c1 int NOT NULL PRIMARY KEY,
	c2 int NULL
)
"
        },
        "none": [
          "Table2.sql"
        ]
      },
      "expected_output": "exit_code=0
package_exists=true
tables=[dbo].[Table1]
views=
